from typing import List
import itertools

class Solution:
    def hasTrailingZeros(self, nums: List[int]) -> bool:
        def ctz(x: int) -> int:
            # number of trailing zeros in binary representation of x
            i = 0
            while (x & 1) == 0:
                x >>= 1
                i += 1
            return i

        n = len(nums)
        for i in range(n):
            for j in range(i + 1, n):
                if ctz(nums[i] | nums[j]) > 0:
                    return True
        return False
